  background: #fff; outline: none; transition: border-color 0.15s;
}
.search-box:focus { border-color: var(--accent); }

.note-list { flex: 1; overflow-y: auto; padding: 4px 0; }
.note-item {
  padding: 10px 16px; cursor: pointer; border-left: 3px solid transparent;
  transition: all 0.1s;
}
.note-item:hover { background: var(--hover); }
.note-item.active { background: var(--active); border-left-color: var(--accent); }
.note-item-title {
  font-size: 13px; font-weight: 500; white-space: nowrap;
  overflow: hidden; text-overflow: ellipsis;
}
.note-item-date { font-size: 11px; color: var(--text-secondary); margin-top: 2px; }
.note-item-match {
  font-size: 11px; color: var(--text-secondary); margin-top: 2px;
  white-space: nowrap; overflow: hidden; text-overflow: ellipsis;
  font-style: italic;
}

/* Main area */
.main { flex: 1; display: flex; flex-direction: column; overflow: hidden; }
.toolbar {
  height: 40px; border-bottom: 1px solid var(--border); display: flex;
  align-items: center; padding: 0 16px; gap: 8px; background: var(--editor-bg);
}
.toolbar .title {
  font-size: 13px; color: var(--text-secondary); flex: 1;
  white-space: nowrap; overflow: hidden; text-overflow: ellipsis;
}
.toolbar .status {
  font-size: 11px; color: var(--text-secondary); transition: opacity 0.3s;
}
.toolbar .status.saving { color: var(--accent); }
.btn-delete {
  background: none; border: none; cursor: pointer; font-size: 12px;
  color: var(--text-secondary); padding: 4px 8px; border-radius: 4px;
  transition: all 0.15s;
}
.btn-delete:hover { background: #fef2f2; color: var(--danger); }

.editor-area { flex: 1; display: flex; overflow: hidden; }

.editor-pane {
  flex: 1; display: flex; flex-direction: column; border-right: 1px solid var(--border);
}
.editor-pane textarea {
  flex: 1; padding: 24px 32px; border: none; outline: none; resize: none;
  font-family: 'JetBrains Mono', monospace; font-size: 14px; line-height: 1.7;
  color: var(--text); background: var(--editor-bg); tab-size: 2;
}
.editor-pane textarea::placeholder { color: #bbb; }

.preview-pane {
  flex: 1; padding: 24px 32px; overflow-y: auto;
  background: var(--preview-bg); font-size: 15px; line-height: 1.7;
}

/* Preview typography */
.preview-pane h1 { font-size: 1.8em; font-weight: 600; margin: 0.4em 0 0.3em; letter-spacing: -0.02em; }
.preview-pane h2 { font-size: 1.4em; font-weight: 600; margin: 1.2em 0 0.3em; letter-spacing: -0.01em; }
.preview-pane h3 { font-size: 1.15em; font-weight: 600; margin: 1em 0 0.3em; }
.preview-pane p { margin: 0.6em 0; }
.preview-pane ul, .preview-pane ol { margin: 0.6em 0; padding-left: 1.5em; }
.preview-pane li { margin: 0.25em 0; }
.preview-pane blockquote {
  border-left: 3px solid var(--border); padding-left: 16px;
  color: var(--text-secondary); margin: 0.8em 0;
}
.preview-pane code {
  font-family: 'JetBrains Mono', monospace; font-size: 0.88em;
  background: #f3f4f6; padding: 2px 5px; border-radius: 3px;
}
.preview-pane pre { margin: 0.8em 0; border-radius: 6px; overflow-x: auto; }
.preview-pane pre code {
  display: block; padding: 16px; background: #f8f9fa;
  font-size: 13px; line-height: 1.5;
}
.preview-pane a { color: var(--accent); text-decoration: none; }
.preview-pane a:hover { text-decoration: underline; }
.preview-pane img { max-width: 100%; border-radius: 4px; }
.preview-pane hr { border: none; border-top: 1px solid var(--border); margin: 1.5em 0; }
.preview-pane table { border-collapse: collapse; width: 100%; margin: 0.8em 0; }
.preview-pane th, .preview-pane td { border: 1px solid var(--border); padding: 8px 12px; text-align: left; }
.preview-pane th { background: #f8f9fa; font-weight: 600; }

/* Empty state */
.empty-state {
  flex: 1; display: flex; align-items: center; justify-content: center;
  color: #bbb; font-size: 14px; flex-direction: column; gap: 8px;
}
.empty-state kbd {
  display: inline-block; padding: 2px 6px; border: 1px solid #ddd;
  border-radius: 3px; font-size: 11px; background: #f5f5f5; font-family: inherit;
}

