<body>
<div class="app">
  <aside class="sidebar">
    <div class="sidebar-header">
      <h1>Notes</h1>
      <button class="btn-new" onclick="createNote()" title="New note (⌘N)">+</button>
    </div>
    <input class="search-box" type="text" placeholder="Search… (⌘⇧F)" id="searchBox">
    <div class="note-list" id="noteList"></div>
  </aside>
  <main class="main" id="mainArea">
    <div class="empty-state" id="emptyState">
      <div>No note selected</div>
      <div><kbd>⌘N</kbd> new note &nbsp; <kbd>⌘S</kbd> save &nbsp; <kbd>⌘⇧F</kbd> search</div>
    </div>
  </main>
</div>

<script>
const $ = s => document.querySelector(s);
let currentNote = null;
let autoSaveTimer = null;
let isSearching = false;

// Marked config
marked.setOptions({
  breaks: true,
  gfm: true,
  highlight: (code, lang) => {
    if (lang && hljs.getLanguage(lang)) {
      return hljs.highlight(code, { language: lang }).value;
    }
    return hljs.highlightAuto(code).value;
  }
});

// --- API ---
const api = {
  async list() { return (await fetch('/api/notes')).json(); },
  async get(id) { return (await fetch(`/api/notes/${id}`)).json(); },
  async create(title) {
    return (await fetch('/api/notes', {
      method: 'POST', headers: {'Content-Type':'application/json'},
      body: JSON.stringify({ title, content: '' })
    })).json();
  },
  async save(id, content) {
    return (await fetch(`/api/notes/${id}`, {
      method: 'PUT', headers: {'Content-Type':'application/json'},
      body: JSON.stringify({ content })
    })).json();
  },
  async remove(id) {
    return (await fetch(`/api/notes/${id}`, { method: 'DELETE' })).json();
  },
  async search(q) { return (await fetch(`/api/search?q=${encodeURIComponent(q)}`)).json(); }
};

// --- Render sidebar ---
async function loadNotes() {
  const notes = await api.list();
  renderNoteList(notes, false);
}

function renderNoteList(notes, showMatch) {
  const list = $('#noteList');
  list.innerHTML = notes.map(n => `
    <div class="note-item ${currentNote?.id === n.id ? 'active' : ''}"
         onclick="openNote('${n.id}')" data-id="${n.id}">
      <div class="note-item-title">${esc(n.title)}</div>
      ${showMatch && n.match ? `<div class="note-item-match">${esc(n.match)}</div>` :
        `<div class="note-item-date">${timeAgo(n.modified)}</div>`}
    </div>
  `).join('');
}

// --- Open note ---
async function openNote(id) {
  // save current first
  if (currentNote && autoSaveTimer) { clearTimeout(autoSaveTimer); await saveNote(); }

  const note = await api.get(id);
  currentNote = note;

  const main = $('#mainArea');
  main.innerHTML = `
    <div class="toolbar">
      <span class="title">${esc(note.title)}</span>
      <span class="status" id="status"></span>
      <button class="btn-delete" onclick="deleteNote()">Delete</button>
    </div>
    <div class="editor-area">
      <div class="editor-pane">
        <textarea id="editor" placeholder="Start writing…">${esc(note.content)}</textarea>
      </div>
      <div class="preview-pane" id="preview"></div>
    </div>
  `;

  const editor = $('#editor');
  updatePreview(editor.value);
  editor.addEventListener('input', onEditorInput);
  editor.focus();

  // Handle tab key for indentation
  editor.addEventListener('keydown', e => {
    if (e.key === 'Tab') {
      e.preventDefault();
      const start = editor.selectionStart;
      const end = editor.selectionEnd;
      editor.value = editor.value.substring(0, start) + '  ' + editor.value.substring(end);
      editor.selectionStart = editor.selectionEnd = start + 2;
      onEditorInput();
    }
  });

  // highlight active in sidebar
  document.querySelectorAll('.note-item').forEach(el => {
    el.classList.toggle('active', el.dataset.id === id);
  });
}

function onEditorInput() {
  const editor = $('#editor');
  updatePreview(editor.value);
  // auto-save after 2s
  clearTimeout(autoSaveTimer);
  const status = $('#status');
  if (status) { status.textContent = 'Editing…'; status.className = 'status'; }
  autoSaveTimer = setTimeout(saveNote, 2000);
}

function updatePreview(md) {
  const preview = $('#preview');
  if (preview) { preview.innerHTML = marked.parse(md); }
}

async function saveNote() {
  if (!currentNote) return;
  const editor = $('#editor');
  if (!editor) return;
  const status = $('#status');
  if (status) { status.textContent = 'Saving…'; status.className = 'status saving'; }

  const updated = await api.save(currentNote.id, editor.value);
  currentNote = { ...currentNote, ...updated, content: editor.value };

  if (status) { status.textContent = 'Saved'; setTimeout(() => { if (status) status.textContent = ''; }, 1500); }

  // refresh sidebar
  if (isSearching) {
    const q = $('#searchBox').value;
    const results = await api.search(q);
    renderNoteList(results, true);
  } else {
    await loadNotes();
  }
}

// --- Create note ---
async function createNote() {
  const note = await api.create('Untitled');
  await loadNotes();
  await openNote(note.id);
  // Select the title text so user can immediately type
  const editor = $('#editor');
  if (editor && editor.value.startsWith('# ')) {
    editor.setSelectionRange(2, editor.value.indexOf('\n') > -1 ? editor.value.indexOf('\n') : editor.value.length);
  }
}

// --- Delete note ---
async function deleteNote() {
  if (!currentNote) return;
  if (!confirm(`Delete "${currentNote.title}"?`)) return;
  await api.remove(currentNote.id);
  currentNote = null;
  $('#mainArea').innerHTML = `
    <div class="empty-state" id="emptyState">
      <div>No note selected</div>
      <div><kbd>⌘N</kbd> new note &nbsp; <kbd>⌘S</kbd> save &nbsp; <kbd>⌘⇧F</kbd> search</div>
    </div>
  `;
  await loadNotes();
}

// --- Search ---
let searchTimer = null;
$('#searchBox').addEventListener('input', e => {
  clearTimeout(searchTimer);
  const q = e.target.value.trim();
  if (!q) {
    isSearching = false;
    loadNotes();
    return;
  }
  isSearching = true;
  searchTimer = setTimeout(async () => {
    const results = await api.search(q);
    renderNoteList(results, true);
  }, 200);
});

// --- Keyboard shortcuts ---
document.addEventListener('keydown', e => {
  const mod = e.metaKey || e.ctrlKey;
  // Cmd+S — save
  if (mod && e.key === 's') {
    e.preventDefault();
    clearTimeout(autoSaveTimer);
    saveNote();
  }
  // Cmd+N — new note
  if (mod && e.key === 'n') {
    e.preventDefault();
    createNote();
  }
  // Cmd+Shift+F — search
  if (mod && e.shiftKey && e.key === 'F') {
    e.preventDefault();
    $('#searchBox').focus();
    $('#searchBox').select();
  }
});

// --- Helpers ---
function esc(s) {
  const d = document.createElement('div');
  d.textContent = s;
  return d.innerHTML;
}

function timeAgo(ts) {
  const diff = (Date.now() / 1000) - ts;
  if (diff < 60) return 'just now';
  if (diff < 3600) return `${Math.floor(diff/60)}m ago`;
  if (diff < 86400) return `${Math.floor(diff/3600)}h ago`;
  return new Date(ts * 1000).toLocaleDateString();
}

// --- Init ---
loadNotes();
</script>
</body>
</html>
