import os
import re
import time
import unicodedata
from pathlib import Path

import uvicorn
from fastapi import FastAPI, HTTPException
from fastapi.staticfiles import StaticFiles
from fastapi.responses import FileResponse
from pydantic import BaseModel

NOTES_DIR = Path(__file__).parent / "notes"
NOTES_DIR.mkdir(exist_ok=True)

app = FastAPI()


class NoteBody(BaseModel):
    content: str
    title: str | None = None


def slugify(text: str) -> str:
    text = unicodedata.normalize("NFKD", text).encode("ascii", "ignore").decode()
    text = re.sub(r"[^\w\s-]", "", text.lower())
    return re.sub(r"[-\s]+", "-", text).strip("-") or "untitled"


def note_path(note_id: str) -> Path:
    safe = Path(note_id).name  # prevent traversal
    p = NOTES_DIR / f"{safe}.md"
    if not p.exists():
        raise HTTPException(404, "Note not found")
    return p


def note_meta(p: Path) -> dict:
    stat = p.stat()
    content = p.read_text(encoding="utf-8")
    first_line = content.split("\n", 1)[0].lstrip("# ").strip() or p.stem
    return {
        "id": p.stem,
        "title": first_line,
        "modified": stat.st_mtime,
        "size": len(content),
    }


@app.get("/api/notes")
def list_notes():
    notes = [note_meta(p) for p in NOTES_DIR.glob("*.md")]
    notes.sort(key=lambda n: n["modified"], reverse=True)
    return notes


@app.post("/api/notes", status_code=201)
def create_note(body: NoteBody):
    title = body.title or "Untitled"
    slug = slugify(title)
    path = NOTES_DIR / f"{slug}.md"
    # avoid collisions
    counter = 1
    while path.exists():
        path = NOTES_DIR / f"{slug}-{counter}.md"
        counter += 1
    content = body.content if body.content else f"# {title}\n\n"
    path.write_text(content, encoding="utf-8")
    return note_meta(path)


@app.get("/api/notes/{note_id}")
def read_note(note_id: str):
    p = note_path(note_id)
    meta = note_meta(p)
    meta["content"] = p.read_text(encoding="utf-8")
    return meta


@app.put("/api/notes/{note_id}")
def update_note(note_id: str, body: NoteBody):
    p = note_path(note_id)
    p.write_text(body.content, encoding="utf-8")
    return note_meta(p)


@app.delete("/api/notes/{note_id}")
def delete_note(note_id: str):
    p = note_path(note_id)
    p.unlink()
    return {"deleted": True}


@app.get("/api/search")
def search_notes(q: str = ""):
    if not q.strip():
        return []
    query = q.lower()
    results = []
    for p in NOTES_DIR.glob("*.md"):
        content = p.read_text(encoding="utf-8")
        if query in content.lower():
            meta = note_meta(p)
            # find first matching line for context
            for line in content.split("\n"):
                if query in line.lower():
                    meta["match"] = line.strip()[:120]
                    break
            results.append(meta)
    results.sort(key=lambda n: n["modified"], reverse=True)
    return results


app.mount("/static", StaticFiles(directory=Path(__file__).parent / "static"), name="static")


@app.get("/")
def index():
    return FileResponse(Path(__file__).parent / "static" / "index.html")


if __name__ == "__main__":
    uvicorn.run(app, host="127.0.0.1", port=8000)
